mapper.select:
SELECT si.*, m.material_name, m.material_type
FROM supplier_item si
JOIN material m ON si.material_id = m.material_id
WHERE si.supplier_id = #{supplierId}
ORDER BY si.supply_available DESC, m.material_name ASC
LIMIT #{perPageNum} OFFSET #{pageStart}

mapper.insert:
INSERT INTO supplier_item (
  supplier_id, material_id, unit_price, unit, supply_available, note
)
VALUES (
  #{supplierId}, #{materialId}, #{unitPrice}, #{unit}, #{supplyAvailable}, #{note}
)

mapper.select:
SELECT COUNT(*) 
FROM supplier_item
WHERE supplier_id = #{supplierId}
  AND material_id = #{materialId}

    AND id != #{id}
